fn add(a: i32, b: i32) -> i32 {
    a + b
}

#[test]
fn test_add() {
    assert_eq!(add(2, 3), 5);
    assert_eq!(add(-1, 1), 0);
}

fn main() {
    println!("add(2, 3) = {}", add(2, 3));
}

fn is_even(n: i32) -> bool {
    n % 2 == 0
}

#[test]
fn test_even() {
    assert!(is_even(4));
    assert!(!is_even(3));
    assert!(is_even(0));
}

fn main() {
    println!("{} {}", is_even(4), is_even(3));
}

fn triple(n: i32) -> i32 {
    n * 3
}

#[test]
fn test_triple() {
    assert_ne!(triple(5), 5);  // 15 != 5
    assert_eq!(triple(4), 12);
}

fn main() {
    println!("{}", triple(5));
}

fn clamp(n: i32, lo: i32, hi: i32) -> i32 {
    n.max(lo).min(hi)
}

#[test]
fn test_clamp() {
    let result = clamp(150, 0, 100);
    assert_eq!(result, 100, "clamp(150, 0, 100) should be 100, got {}", result);
    assert!(result >= 0 && result <= 100, "result {} out of range", result);
}

fn main() {
    println!("{}", clamp(150, 0, 100));
}

fn divide(a: i32, b: i32) -> i32 {
    if b == 0 { panic!("division by zero!"); }
    a / b
}

#[test]
#[should_panic(expected = "division by zero")]
fn test_divide_by_zero() {
    divide(10, 0); // should panic
}

fn main() {
    println!("{}", divide(10, 2));
}

